glsl.vertex:
varying vec2 vUv;
varying vec3 vPos;
void main(){
 vUv = uv;
 vPos = position;
 gl_Position = projectionMatrix * modelViewMatrix * vec4(position,1.0);
}

glsl.fragment:
precision highp float;
varying vec2 vUv;
uniform vec3 uBg;
uniform vec3 uPrimary;
uniform vec3 uSecondary;
uniform vec3 uGlow;
uniform vec3 uAnchor;
uniform float uTime;
uniform float uSeed;
float hash(vec2 p){ return fract(sin(dot(p, vec2(127.1,311.7)) + uSeed*13.7) * 43758.5453123); }
float noise(vec2 p){
 vec2 i = floor(p); vec2 f = fract(p);
 float a = hash(i), b = hash(i+vec2(1.0,0.0)), c = hash(i+vec2(0.0,1.0)), d = hash(i+vec2(1.0,1.0));
 vec2 u = f*f*(3.0-2.0*f);
 return mix(a,b,u.x) + (c-a)*u.y*(1.0-u.x) + (d-b)*u.x*u.y;
}
float fbm(vec2 p){
 float v = 0.0;
 float a = 0.5;
 for(int i=0;i<5;i++){
 v += a * noise(p);
 p = p * 2.03 + vec2(17.0,11.0);
 a *= 0.5;
 }
 return v;
}
void main(){
 vec2 uv = vUv * 2.0 - 1.0;
 float vertical = smoothstep(-0.95, 0.9, uv.y);
 float fieldA = fbm(vec2(uv.x*1.1, uv.y*0.8) * 2.2);
 float fieldB = fbm(vec2(uv.x*0.7 + 4.0, uv.y*1.5 - 2.0) * 2.8);
 float fieldC = fbm(vec2(uv.x*2.0 - 3.0, uv.y*0.5 + 7.0) * 3.1);
 float cleft = abs(uv.x + 0.18*sin(uv.y*2.7) - 0.12*fieldB + 0.16*(vertical-0.5));
 float seam = 1.0 - smoothstep(0.02, 0.16, cleft);
 float warmMass = smoothstep(0.28, 0.8, fieldA + vertical*0.35 - uv.x*0.15);
 float coolMass = smoothstep(0.42, 0.86, fieldC + (1.0-vertical)*0.2 + uv.x*0.22);
 float scrape = pow(fbm(uv*8.0 + vec2(0.0, uTime*0.02)), 2.2);
 vec3 col = uBg;
 col = mix(col, uPrimary, warmMass*0.82);
 col = mix(col, uSecondary, coolMass*0.48);
 col += uGlow * seam * (0.45 + 0.35*vertical);
 col += uAnchor * pow(seam, 3.0) * (0.35 + 0.65*vertical);
 col *= 0.92 + 0.18*scrape;
 float edgeStress = smoothstep(0.48, 0.56, abs(fieldA-fieldB));
 col = mix(col, col*0.82, edgeStress*0.25);
 gl_FragColor = vec4(col, 1.0);
}
